	fail, ok := t.failOnEvent.LoadAndDelete(eventName)
	if ok && fail.(bool) {
		return fmt.Errorf("mock handler error for %q", eventName)
	}

	return nil
}

func (t *TestHandlerBase) addEvent(eventName string, param any) error {
	if err := t.checkFailOnEvent(eventName); err != nil {
		return err
	}

	ev := TestEvent{
		Name:      eventName,
		Parameter: param,
		Handler:   t.Name,
	}

	select {
	case t.Events <- ev:
		return nil
	case <-time.After(5 * time.Second):
		return fmt.Errorf("timeout sending event %q to channel", eventName)
	}
}

func (t *TestHandlerBase) Init(_ context.Context) error {
	t.Initialized = true
	return t.checkFailOnEvent(EvInit)
}

func (t *TestHandlerBase) GetName() string {
	return t.Name
}

func (t *TestHandlerBase) GetNetworkPlugins() []string {
	return []string{t.NetworkPlugin}
}

